const e=`{% block sw_privilege_error %} <sw-page class="sw-privilege-error"> {% block sw_privilege_error_inner %} <template #content> {% block sw_privilege_error_inner_content %} <div class="sw-privilege-error__content"> {% block sw_privilege_error_inner_content_image %} <img class="sw-privilege-error__access-denied-image" :src="assetFilter('administration/administration/static/img/privileges/access-denied.svg')" alt="" > {% endblock %} {% block sw_privilege_error_inner_content_headline %} <h1>{{ $t('sw-privilege-error.general.mainMenuItemGeneral') }}</h1> {% endblock %} {% block sw_privilege_error_inner_content_description %} <p>{{ $t('sw-privilege-error.general.descriptionTextModule') }}</p> {% endblock %} {% block sw_privilege_error_inner_content_back_button %} <mt-button variant="primary" class="sw-privilege-error__back-button" @click="routerGoBack" > {{ $t('sw-privilege-error.general.goBack') }} </mt-button> {% endblock %} </div> {% endblock %} </template> {% endblock %} </sw-page> {% endblock %}`,r={template:e,metaInfo(){return{title:this.$createTitle(this.identifier)}},computed:{assetFilter(){return Shopware.Filter.getByName("asset")}},methods:{routerGoBack(){this.$router.go(-1)}}};export{r as default};
